mapper.select:
SELECT * FROM attendance_record
WHERE emp_id = #{empId}
    AND YEAR(record_date) = #{year}
  AND MONTH(record_date) = #{month}

SELECT ar.* FROM attendance_record ar
                     JOIN employee e ON ar.emp_id = e.emp_id
WHERE e.emp_name LIKE CONCAT('%', #{empName}, '%')
    AND YEAR(ar.record_date) = #{year}
  AND MONTH(ar.record_date) = #{month}
ORDER BY ar.record_date

SELECT * FROM attendance_record
                  JOIN employee ON attendance_record.emp_id = employee.emp_id
WHERE employee.dept_id = #{deptId}
    AND YEAR(attendance_record.record_date) = #{year}
  AND MONTH(attendance_record.record_date) = #{month}

SELECT * FROM attendance_record
WHERE YEAR(record_date) = #{year}
  AND MONTH(record_date) = #{month}
